package log.org.apache.karaf.log.command;

private final class LogServiceTracker extends ServiceTracker < LogService , LogService > { private final static String SSHD_LOGGER = "org.apache.sshd" ; private final PaxAppender appender ; private String sshdLoggerLevel ; private LogServiceTracker ( BundleContext context , Class < LogService > clazz , ServiceTrackerCustomizer < LogService , LogService > customizer , PaxAppender appender ) { super ( context , clazz , customizer ) ; this . appender = appender ; } @ Override public LogService addingService ( ServiceReference < LogService > reference ) { LogService service = super . addingService ( reference ) ; sshdLoggerLevel = service . getLevel ( SSHD_LOGGER ) . get ( SSHD_LOGGER ) ; service . setLevel ( SSHD_LOGGER , "ERROR" ) ; service . addAppender ( appender ) ; return service ; } @ Override public void removedService ( ServiceReference < LogService > reference , LogService service ) { if ( sshdLoggerLevel != null ) { service . setLevel ( SSHD_LOGGER , sshdLoggerLevel ) ; } service . removeAppender ( appender ) ; stopTail ( ) ; } }